bash_commands.command:
cd /app && node -e "
const { pluginNamePattern, themeNamePattern } = require('./src/constants');
console.log('Test 1 - Valid plugin name:');
console.log('nodebb-plugin-imgur:', pluginNamePattern.test('nodebb-plugin-imgur'));
console.log('Test 2 - Valid theme name:');
console.log('nodebb-theme-persona:', themeNamePattern.test('nodebb-theme-persona'));
console.log('Test 3 - Invalid name with whitespace:');
console.log('\\t\\nnodebb-plugin:', pluginNamePattern.test('\t\nnodebb-plugin'));
console.log('Test 4 - Invalid name (not a plugin):');
console.log('notaplugin:', pluginNamePattern.test('notaplugin'));
console.log('Test 5 - Scoped plugin:');
console.log('@nodebb/nodebb-plugin-abc:', pluginNamePattern.test('@nodebb/nodebb-plugin-abc'));
"

cd /app && node -e "
const patterns = require('./src/constants');
const pluginNamePattern = patterns.pluginNamePattern;
const themeNamePattern = patterns.themeNamePattern;

console.log('Testing validation patterns:');
console.log('');

const testCases = [
  { id: 'nodebb-plugin-imgur', expected: true, desc: 'Valid plugin' },
  { id: 'nodebb-theme-persona', expected: true, desc: 'Valid theme' },
  { id: '@nodebb/nodebb-plugin-abc', expected: true, desc: 'Scoped plugin' },
  { id: '@nodebb/nodebb-theme-xyz', expected: true, desc: 'Scoped theme' },
  { id: '\t\nnodebb-plugin', expected: false, desc: 'Plugin with whitespace' },
  { id: 'notaplugin', expected: false, desc: 'Invalid name' },
  { id: 'plugin-imgur', expected: false, desc: 'Missing prefix' },
  { id: '', expected: false, desc: 'Empty string' },
  { id: 'nodebb-widget-essentials', expected: true, desc: 'Widget plugin' },
  { id: 'nodebb-rewards-points', expected: true, desc: 'Rewards plugin' },
];

testCases.forEach(test => {
  const result = pluginNamePattern.test(test.id) || themeNamePattern.test(test.id);
  const status = result === test.expected ? '✓' : '✗';
  console.log(\`\${status} \${test.desc}: '\${test.id}' => \${result} (expected: \${test.expected})\`);
});
"

